// src/components/MyPet/MyPetProfile.jsx

import React, { useState, useEffect } from "react";
import axios from "axios";
import './MyPetProfile.css';

function MyPetProfile() {
    const [petProfile, setPetProfile] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        fetchPetProfile();
    }, []);

    const fetchPetProfile = async () => {
        try {
            const response = await axios.get('http://localhost:8080/api/pet/profile/pets', {
                withCredentials: true
            });

            // 배열 형태로 데이터가 오므로 첫 번째 항목 선택
            const pets = response.data;
            console.log("받은 데이터:", pets); // 디버깅용

            if (pets && pets.length > 0) {
                const petData = pets[0];
                console.log("펫 프로필 데이터:", petData); // 디버깅용
                console.log("이미지 URL:", petData.profileImageUrl); // 디버깅용
                setPetProfile(petData);
            } else {
                setPetProfile(null);
            }
        } catch (error) {
            console.error("프로필 조회 실패:", error);
            setError("프로필을 불러오는데 실패했습니다.");
        } finally {
            setIsLoading(false);
        }
    };

    const getImageUrl = (imageUrl) => {
        if (!imageUrl) return null;

        // 이미 완전한 URL인 경우
        if (imageUrl.startsWith('http://') || imageUrl.startsWith('https://')) {
            return imageUrl;
        }

        // 상대 경로인 경우 서버 주소 추가
        if (imageUrl.startsWith('/')) {
            return `http://localhost:8080${imageUrl}`;
        }

        // 기타 경우 (uploads/image.jpg 같은 형태)
        return `http://localhost:8080/${imageUrl}`;
    };

    const formatDate = (dateString) => {
        if (!dateString) return "등록되지 않음";
        const date = new Date(dateString);
        return date.toLocaleDateString('ko-KR');
    };

    const getGenderText = (gender) => {
        switch (gender) {
            case 'FEMALE': return '암컷';
            case 'MALE': return '수컷';
            case 'NEUTER': return '중성';
            default: return '알 수 없음';
        }
    };

    const getSizeText = (size) => {
        switch (size) {
            case 'SMALL': return '소형견';
            case 'MEDIUM': return '중형견';
            case 'LARGE': return '대형견';
            default: return '알 수 없음';
        }
    };

    const getAdoptText = (adopt) => {
        return adopt ? '입양견' : '일반견';
    };

    if (isLoading) {
        return (
            <div className="mypet-profile-container">
                <div className="mypet-profile-card">
                    <div className="loading-spinner-large"></div>
                    <p>프로필을 불러오는 중...</p>
                </div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="mypet-profile-container">
                <div className="mypet-profile-card">
                    <div className="error-message-large">{error}</div>
                    <button onClick={fetchPetProfile} className="retry-btn">
                        다시 시도
                    </button>
                </div>
            </div>
        );
    }

    if (!petProfile) {
        return (
            <div className="mypet-profile-container">
                <div className="mypet-profile-card">
                    <div className="no-profile">
                        <div className="paw-icon">🐾</div>
                        <h2>등록된 반려견이 없습니다</h2>
                        <p>아직 반려견 프로필을 등록하지 않으셨네요.</p>
                        <button onClick={() => window.location.href = '/mypet/register'} className="register-btn">
                            반려견 등록하기
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="mypet-profile-container">
            <div className="mypet-profile-card">
                <div className="profile-header">
                    <div className="paw-icon">🐾</div>
                    <h2>나의 반려견 프로필</h2>
                    <p>소중한 반려견의 정보입니다</p>
                </div>

                <div className="profile-content">
                    <div className="profile-image-section">
                        {petProfile.profile ? (
                            <img
                                src={getImageUrl(petProfile.profile)}
                                alt={`${petProfile.name}의 프로필 사진`}
                                className="profile-image"
                                onLoad={() => console.log('이미지 로드 성공:', getImageUrl(petProfile.profile))}
                                onError={(e) => {
                                    console.error('이미지 로드 실패:', getImageUrl(petProfile.profile));
                                    e.target.style.display = 'none';
                                    e.target.nextSibling.style.display = 'block';
                                }}
                            />
                        ) : (
                            <div className="no-image">
                                <span>📷</span>
                                <p>프로필 사진 없음</p>
                            </div>
                        )}

                        {/* 이미지 로드 실패 시 보여줄 대체 요소 */}
                        <div className="no-image" style={{ display: 'none' }}>
                            <span>❌</span>
                            <p>이미지를 불러올 수 없습니다</p>
                        </div>
                    </div>

                    <div className="profile-info">
                        <div className="info-section">
                            <h3>기본 정보</h3>
                            <div className="info-grid">
                                <div className="info-item">
                                    <label>이름</label>
                                    <span>{petProfile.name}</span>
                                </div>
                                <div className="info-item">
                                    <label>품종</label>
                                    <span>{petProfile.type}</span>
                                </div>
                                <div className="info-item">
                                    <label>성별</label>
                                    <span>{getGenderText(petProfile.gender)}</span>
                                </div>
                                <div className="info-item">
                                    <label>나이</label>
                                    <span>{petProfile.age}살</span>
                                </div>
                                <div className="info-item">
                                    <label>몸무게</label>
                                    <span>{petProfile.weight}kg</span>
                                </div>
                                <div className="info-item">
                                    <label>크기</label>
                                    <span>{getSizeText(petProfile.size)}</span>
                                </div>
                            </div>
                        </div>

                        <div className="info-section">
                            <h3>등록 정보</h3>
                            <div className="info-grid">
                                <div className="info-item">
                                    <label>등록번호</label>
                                    <span>{petProfile.petId}</span>
                                </div>
                                <div className="info-item">
                                    <label>입양 여부</label>
                                    <span className={`adopt-badge ${petProfile.adopt ? 'adopted' : 'not-adopted'}`}>
                                        {getAdoptText(petProfile.adopt)}
                                    </span>
                                </div>
                                <div className="info-item">
                                    <label>등록일</label>
                                    <span>{formatDate(petProfile.createdAt)}</span>
                                </div>
                            </div>
                        </div>

                        {petProfile.profile && (
                            <div className="info-section">
                                <h3>특이사항</h3>
                                <div className="profile-text">
                                    {petProfile.profile}
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                <div className="profile-actions">
                    <button onClick={() => window.location.href = '/mypet/edit'} className="edit-btn">
                        프로필 수정
                    </button>
                    <button onClick={() => window.location.href = '/mypet/register'} className="register-btn">
                        새로운 반려견 등록
                    </button>
                </div>
            </div>
        </div>
    );
}

export default MyPetProfile;
